class SparkViewKeyView extends ConsumerStatefulWidget {
  const SparkViewKeyView({
    super.key,
    required this.walletId,
    required this.sparkViewKeyHex,
    this.clipboardInterface = const ClipboardWrapper(),
    this.showDesktopDialogTitle = true,
  });

  final String walletId;
  final String sparkViewKeyHex;
  final ClipboardInterface clipboardInterface;
  final bool showDesktopDialogTitle;

  static const String routeName = "/spark_view_key";

  @override
  ConsumerState<SparkViewKeyView> createState() => _SparkViewKeyViewState();
}

class _SparkViewKeyViewState extends ConsumerState<SparkViewKeyView> {
  Future<void> _copy() async {
    await widget.clipboardInterface.setData(
      ClipboardData(text: widget.sparkViewKeyHex),
    );
    if (mounted) {
      unawaited(
        showFloatingFlushBar(
          type: FlushBarType.info,
          message: "Copied to clipboard",
          iconAsset: Assets.svg.copy,
          context: context,
        ),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    final bool isDesktop = Util.isDesktop;

    return ConditionalParent(
      condition: !isDesktop,
      builder: (child) => Background(
        child: Scaffold(
          backgroundColor: Theme.of(
            context,
          ).extension<StackColors>()!.background,
          appBar: AppBar(
            leading: AppBarBackButton(
              onPressed: () async {
                Navigator.of(context).pop();
              },
            ),
            title: Text(
              "Spark View Key",
              style: STextStyles.navBarTitle(context),
            ),
          ),
          body: SafeArea(
            child: Padding(
              padding: const EdgeInsets.only(top: 12, left: 16, right: 16),
              child: LayoutBuilder(
                builder: (context, constraints) => SingleChildScrollView(
                  child: ConstrainedBox(
                    constraints: BoxConstraints(
                      minHeight: constraints.maxHeight,
                    ),
                    child: IntrinsicHeight(
                      child: Column(
                        children: [
                          Expanded(child: child),
                          const SizedBox(height: 16),
                        ],
                      ),
                    ),
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
      child: ConditionalParent(
        condition: isDesktop && widget.showDesktopDialogTitle,
        builder: (child) => DesktopDialog(
          maxWidth: 600,
          maxHeight: double.infinity,
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Row(
                mainAxisAlignment: MainAxisAlignment.spaceBetween,
                children: [
                  Padding(
                    padding: const EdgeInsets.only(left: 32),
                    child: Text(
                      "Spark View Key",
                      style: STextStyles.desktopH2(context),
                    ),
                  ),
                  DesktopDialogCloseButton(
                    onPressedOverride: Navigator.of(
                      context,
                      rootNavigator: true,
                    ).pop,
                  ),
                ],
              ),
              Flexible(
                child: Padding(
                  padding: const EdgeInsets.fromLTRB(32, 0, 32, 32),
                  child: SingleChildScrollView(child: child),
                ),
              ),
            ],
          ),
        ),
        child: Column(
          mainAxisSize: Util.isDesktop ? MainAxisSize.min : MainAxisSize.max,
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [
            SizedBox(height: Util.isDesktop ? 12 : 16),
            QR(
              data: widget.sparkViewKeyHex,
              size: Util.isDesktop
                  ? 256
                  : MediaQuery.of(context).size.width / 1.5,
            ),
            SizedBox(height: Util.isDesktop ? 12 : 16),
            RoundedWhiteContainer(
              borderColor: Util.isDesktop
                  ? Theme.of(
                      context,
                    ).extension<StackColors>()!.textFieldDefaultBG
                  : null,
              child: SelectableText(
                widget.sparkViewKeyHex,
                style: STextStyles.w500_14(context),
              ),
            ),
            SizedBox(height: Util.isDesktop ? 12 : 16),
            if (!Util.isDesktop) const Spacer(),
            Row(
              children: [
                if (Util.isDesktop) const Spacer(),
                if (Util.isDesktop) const SizedBox(width: 16),
                Expanded(
                  child: PrimaryButton(label: "Copy", onPressed: _copy),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }
}
